   757	FunctionDecl*
   758	Ast2Asg::operator()(ast::FunctionDefinitionContext* ctx)
   759	{
   760	  auto ret = make<FunctionDecl>();
   761	  mCurrentFunc = ret;
   762	
   763	  auto type = make<Type>();
   764	  ret->type = type;
   765	
   766	  auto sq = self(ctx->declarationSpecifiers());
   767	  type->spec = sq.first, type->qual = sq.second;
   768	
   769	  // Parse the directDeclarator which may include parameters
   770	  // This also populates mParamInfos
   771	  auto [texp, name] = self(ctx->directDeclarator(), nullptr);
   772	  ret->name = std::move(name);
   773	
   774	  // The texp might be a FunctionType if the directDeclarator had parameters
   775	  if (auto* ft = texp->dcst<FunctionType>()) {
   776	    type->texp = ft;
   777	    // Create VarDecl for each parameter using mParamInfos
   778	    for (size_t i = 0; i < mParamInfos.size(); ++i) {
   779	      auto paramDecl = make<VarDecl>();
   780	      paramDecl->type = mParamInfos[i].type;
   781	      paramDecl->name = mParamInfos[i].name;
   782	      ret->params.push_back(paramDecl);
   783	    }
   784	  } else {
   785	    auto funcType = make<FunctionType>();
   786	    funcType->sub = texp;
   787	    type->texp = funcType;
   788	  }
   789	
   790	  Symtbl localDecls(self);
   791	
   792	  // 函数定义在签名之后就加入符号表，以允许递归调用
   793	  (*mSymtbl)[ret->name] = ret;
   794	
   795	  // Add parameters to symbol table
   796	  for (auto&& param : ret->params) {
   797	    (*mSymtbl)[param->name] = param;
   798	  }
   799	
   800	  ret->body = self(ctx->compoundStatement());
